import React, { useState, useMemo } from "react";
import { 
  theme, 
  Typography, 
  Table, 
  Button, 
  Input, 
  Space, 
  Modal, 
  Form, 
  Select, 
  InputNumber, 
  message 
} from "antd";
import { 
  PlusOutlined, 
  EditOutlined, 
  DeleteOutlined, 
  SearchOutlined, 
  FileExcelOutlined,
  ExclamationCircleOutlined
} from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { PLANTS } from "../../dashboard/data/mockData";

const { Text, Title } = Typography;
const { useToken } = theme;
const { Option } = Select;

interface AreaData {
  key: string;
  domainName: string;
  areaName: string;
  sortOrder: number;
  description: string;
}

export default function AreaManagement() {
  const { token } = useToken();
  const { t } = useI18n(["settings"]);
  const [data, setData] = useState<AreaData[]>(() => 
    PLANTS.map(p => ({
      key: p.id.toString(),
      domainName: "M-Safety 사이트",
      areaName: p.name,
      sortOrder: p.id,
      description: `${p.name} 안전 관제 구역`,
    }))
  );
  const [selectedRowKeys, setSelectedRowKeys] = useState<React.Key[]>([]);
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [editingArea, setEditingArea] = useState<AreaData | null>(null);
  const [form] = Form.useForm();

  // Columns using i18n
  const columns = [
    {
      title: t("area_management.columns.domain", { ns: "settings" }),
      dataIndex: "domainName",
      key: "domainName",
      sorter: (a: AreaData, b: AreaData) => a.domainName.localeCompare(b.domainName),
    },
    {
      title: t("area_management.columns.area", { ns: "settings" }),
      dataIndex: "areaName",
      key: "areaName",
      sorter: (a: AreaData, b: AreaData) => a.areaName.localeCompare(b.areaName),
    },
    {
      title: t("area_management.columns.sort", { ns: "settings" }),
      dataIndex: "sortOrder",
      key: "sortOrder",
      sorter: (a: AreaData, b: AreaData) => a.sortOrder - b.sortOrder,
    },
    {
      title: t("area_management.columns.description", { ns: "settings" }),
      dataIndex: "description",
      key: "description",
    },
  ];

  const handleAdd = () => {
    setEditingArea(null);
    form.resetFields();
    setIsModalVisible(true);
  };

  const handleEdit = () => {
    if (selectedRowKeys.length !== 1) {
      message.warning(t("area_management.messages.select_one_to_edit", { ns: "settings" }));
      return;
    }
    const target = data.find(it => it.key === selectedRowKeys[0]);
    if (target) {
      setEditingArea(target);
      form.setFieldsValue(target);
      setIsModalVisible(true);
    }
  };

  const handleDelete = () => {
    if (selectedRowKeys.length === 0) {
      message.warning(t("area_management.messages.select_to_delete", { ns: "settings" }));
      return;
    }
    Modal.confirm({
      title: t("area_management.messages.delete_confirm_title", { ns: "settings" }),
      icon: <ExclamationCircleOutlined />,
      content: t("area_management.messages.delete_confirm_content", { ns: "settings" }),
      okText: t("area_management.form.save", { ns: "settings" }), // Use t() for confirm strings
      cancelText: t("area_management.form.close", { ns: "settings" }),
      okButtonProps: { danger: true },
      onOk() {
        setData(data.filter(it => !selectedRowKeys.includes(it.key)));
        setSelectedRowKeys([]);
        message.success(t("area_management.messages.delete_success", { ns: "settings" }));
      },
    });
  };

  const handleSave = () => {
    form.validateFields().then(values => {
      if (editingArea) {
        setData(data.map(it => it.key === editingArea.key ? { ...it, ...values } : it));
        message.success(t("area_management.messages.save_success_edit", { ns: "settings" }));
      } else {
        const newData = { ...values, key: (data.length + 1).toString() };
        setData([...data, newData]);
        message.success(t("area_management.messages.save_success_add", { ns: "settings" }));
      }
      setIsModalVisible(false);
    });
  };

  const handleExcelDownload = () => {
    if (data.length === 0) {
      message.warning(t("area_management.messages.excel_no_data", { ns: "settings" }));
      return;
    }

    const headers = [
      t("area_management.columns.domain", { ns: "settings" }),
      t("area_management.columns.area", { ns: "settings" }),
      t("area_management.columns.sort", { ns: "settings" }),
      t("area_management.columns.description", { ns: "settings" })
    ];
    const csvContent = [headers.join(","), ...data.map(item => [item.domainName, item.areaName, item.sortOrder, item.description].join(","))].join("\n");
    const blob = new Blob(["\ufeff" + csvContent], { type: "text/csv;charset=utf-8;" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `AreaManagement_${new Date().toISOString().slice(0, 10)}.csv`;
    link.click();
    message.success(t("area_management.messages.excel_success", { ns: "settings" }));
  };

  return (
    <div style={{ padding: "24px", background: token.colorBgLayout, minHeight: "100%" }}>
      <div style={{ marginBottom: 24, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <Title level={3} style={{ margin: 0 }}>{t("area_management.title", { ns: "settings" })}</Title>
        <Space size="middle">
          <Button icon={<PlusOutlined />} onClick={handleAdd}>{t("area_management.add", { ns: "settings" })}</Button>
          <Button icon={<EditOutlined />} onClick={handleEdit}>{t("area_management.edit", { ns: "settings" })}</Button>
          <Button danger icon={<DeleteOutlined />} onClick={handleDelete}>{t("area_management.delete", { ns: "settings" })}</Button>
          <Button icon={<SearchOutlined />}>{t("area_management.search", { ns: "settings" })}</Button>
          <Button icon={<FileExcelOutlined />} onClick={handleExcelDownload}>{t("area_management.excel", { ns: "settings" })}</Button>
          <Input 
            placeholder={t("area_management.search_placeholder", { ns: "settings" })} 
            prefix={<SearchOutlined style={{ color: token.colorTextDescription }} />} 
            style={{ width: 200 }}
          />
        </Space>
      </div>

      <div style={{ background: token.colorBgContainer, padding: 16, borderRadius: token.borderRadiusLG, boxShadow: token.boxShadowTertiary, border: `1px solid ${token.colorBorderSecondary}` }}>
        <Table 
          rowSelection={{
            type: "checkbox",
            selectedRowKeys,
            onChange: (keys) => setSelectedRowKeys(keys),
          }}
          columns={columns} 
          dataSource={data} 
          pagination={{
            showSizeChanger: true,
            defaultPageSize: 10,
            pageSizeOptions: ['10', '20', '30'],
            showTotal: (total, range) => `${total} 중 ${range[0]}-${range[1]}`,
          }}
        />
      </div>

      {/* Add/Edit Modal - Unified Style & I18n */}
      <Modal
        title={
          <div style={{ 
            margin: "-16px -24px", 
            padding: "16px 24px", 
            background: token.colorPrimary, 
            color: "white", 
            borderRadius: `${token.borderRadiusLG}px ${token.borderRadiusLG}px 0 0`,
            fontSize: 18,
            fontWeight: 700
          }}>
            {t("area_management.form.modal_title", { ns: "settings" })}
          </div>
        }
        open={isModalVisible}
        onOk={handleSave}
        onCancel={() => setIsModalVisible(false)}
        footer={[
          <Button key="cancel" onClick={() => setIsModalVisible(false)} style={{ height: 40, width: 80, borderRadius: token.borderRadius }}>
            {t("area_management.form.close", { ns: "settings" })}
          </Button>,
          <Button key="save" type="primary" onClick={handleSave} style={{ height: 40, width: 80, borderRadius: token.borderRadius }}>
            {t("area_management.form.save", { ns: "settings" })}
          </Button>,
        ]}
        centered
        width={500}
        closeIcon={<span style={{ color: "white" }}>X</span>}
      >
        <div style={{ paddingTop: 24 }}>
          <Form form={form} layout="vertical" initialValues={{ sortOrder: 1 }}>
            <Form.Item 
              name="domainName" 
              label={<Text strong>{t("area_management.form.domain_label", { ns: "settings" })}</Text>}
              rules={[{ required: true, message: t("area_management.form.domain_placeholder", { ns: "settings" }) }]}
            >
              <Select placeholder={t("area_management.form.domain_placeholder", { ns: "settings" })} showSearch style={{ height: 40 }}>
                <Option value="사이트1">사이트1</Option>
                <Option value="사이트2">사이트2</Option>
                <Option value="사이트3">사이트3</Option>
              </Select>
            </Form.Item>
            <Form.Item 
              name="areaName" 
              label={<Text strong>{t("area_management.form.area_label", { ns: "settings" })}</Text>}
              rules={[{ required: true, message: t("area_management.form.area_placeholder", { ns: "settings" }) }]}
            >
              <Input placeholder={t("area_management.form.area_placeholder", { ns: "settings" })} style={{ height: 40 }} />
            </Form.Item>
            <Form.Item 
              name="sortOrder" 
              label={<Text strong>{t("area_management.form.sort_label", { ns: "settings" })}</Text>}
              rules={[{ required: true, message: t("area_management.form.sort_label", { ns: "settings" }) }]}
            >
              <InputNumber style={{ width: "100%", height: 40 }} min={1} />
            </Form.Item>
            <Form.Item 
              name="description" 
              label={<Text strong>{t("area_management.form.description_label", { ns: "settings" })}</Text>}
            >
              <Input.TextArea rows={6} placeholder={t("area_management.form.description_placeholder", { ns: "settings" })} />
            </Form.Item>
          </Form>
        </div>
      </Modal>

      <style>{`
        .ant-table-thead > tr > th {
          background-color: ${token.colorFillAlter} !important;
          font-weight: 700 !important;
        }
        .ant-table-row:hover {
          cursor: pointer;
        }
      `}</style>
    </div>
  );
}
